### 2. `viz/lib/utils.ts` — shared utility functions

```typescript
export function confColor(conf: number): string {
  if (conf <= 0) return '#374151'
  const r = Math.round(239 - conf * (239 - 34))
  const g = Math.round(68  + conf * (197 - 68))
  const b = Math.round(68  + conf * (94  - 68))
  return `rgb(${r},${g},${b})`
}

export const formatConf = (c: number) => c.toFixed(3)

export const cn = (...classes: (string | undefined | false)[]) =>
  classes.filter(Boolean).join(' ')
```

