### 4. `viz/lib/hooks/useInferenceStream.ts` — thin wrapper (5 lines)

```typescript
'use client'
import { useEventStream } from './useEventStream'
import { apiUrl } from '../api'

export type InferenceEvent =
  | { type: 'unmask';     block_idx: number; step_idx: number; position: number;
      token_id: number; confidence: number; entropy: number }
  | { type: 'block_step'; block_idx: number; step_idx: number;
      n_total_masked: number; n_unmasked_now: number; token_sequence: number[] }
  | { type: 'logit_capture'; block_idx: number; step_idx: number;
      positions: number[]; top_k_ids: number[][]; top_k_probs: number[][] }
  | { type: 'done'; session_id: string }

export function useInferenceStream(sessionId: string | null) {
  return useEventStream<InferenceEvent>(
    sessionId ? apiUrl(`/api/session/${sessionId}/stream`) : null,
    (raw) => JSON.parse(raw) as InferenceEvent
  )
}
```

