interface Props {
  cursor: number; total: number; playing: boolean
  onFirst: () => void; onPrev: () => void
  onPlayPause: () => void; onNext: () => void; onLast: () => void
}
export default function PlaybackControls(
  { cursor, total, playing, onFirst, onPrev, onPlayPause, onNext, onLast }: Props
) {
  return (
    <div className="flex items-center gap-2 text-sm">
      <button onClick={onFirst}>&#9198;</button>
      <button onClick={onPrev}>&#9664;</button>
      <button onClick={onPlayPause}>{playing ? '\u23F8' : '\u25B6'}</button>
      <button onClick={onNext}>&#9654;</button>
      <button onClick={onLast}>&#9197;</button>
      <span className="ml-2 text-gray-400">step {cursor + 1} / {total}</span>
    </div>
  )
}
