'use client'
import { confColor, formatConf } from '@/lib/utils'
import { MASK_ID } from '@/lib/constants'

interface Props {
  tokens: number[]; confidences: number[]; onSelect?: (pos: number) => void
}
export default function TokenGrid({ tokens, confidences, onSelect }: Props) {
  return (
    <div className="flex flex-wrap gap-1 font-mono text-xs">
      {tokens.map((tid, pos) => (
        <button key={pos} onClick={() => onSelect?.(pos)}
          title={`pos=${pos} tok=${tid} conf=${formatConf(confidences[pos] ?? 0)}`}
          style={{ background: confColor(confidences[pos] ?? 0) }}
          className="px-1.5 py-0.5 rounded text-white transition-all duration-300">
          {tid === MASK_ID ? '\u2591' : String(tid).slice(0, 4)}
        </button>
      ))}
    </div>
  )
}
