### 8. `viz/components/BlockStepper.tsx` — uses PlaybackControls

```typescript
'use client'
import React, { useState, useEffect, useRef } from 'react'
import PlaybackControls from './ui/PlaybackControls'

interface Step {
  block_idx: number; step_idx: number
  token_sequence: number[]; n_total_masked: number; n_unmasked_now: number
}
interface Props { steps: Step[]; onStep: (s: Step) => void }

export default function BlockStepper({ steps, onStep }: Props) {
  const [cursor, setCursor] = useState(0)
  const [playing, setPlaying] = useState(false)
  const timer = useRef<ReturnType<typeof setInterval> | null>(null)

  useEffect(() => { if (steps[cursor]) onStep(steps[cursor]) }, [cursor, steps])

  useEffect(() => {
    if (playing) timer.current = setInterval(() =>
      setCursor(c => Math.min(c + 1, steps.length - 1)), 300)
    else if (timer.current) clearInterval(timer.current)
    return () => { if (timer.current) clearInterval(timer.current) }
  }, [playing, steps.length])

  return (
    <PlaybackControls
      cursor={cursor} total={steps.length} playing={playing}
      onFirst={() => setCursor(0)}
      onPrev={() => setCursor(c => Math.max(0, c - 1))}
      onPlayPause={() => setPlaying(p => !p)}
      onNext={() => setCursor(c => Math.min(c + 1, steps.length - 1))}
      onLast={() => setCursor(steps.length - 1)}
    />
  )
}
```

